1	import { createReadStream, existsSync, statSync } from "node:fs";
2	import os from "node:os";
3	import path from "node:path";
4	import { Readable } from "node:stream";
5	import {
6		BrandProfileSchema,
7		fetchMarketContext,
8		fetchRepoSnapshot,
9		parseRepoUrl,
10		writeScriptFromRepo,
11	} from "@content-factory/agent";
12	import { renderVideo } from "@content-factory/composer";
13	import { Hono } from "hono";
14	import { streamSSE } from "hono/streaming";
15	import { z } from "zod";
16	import { synthesizeVoice } from "../lib/gradium";
17	import { createJob, getJob, type Job, subscribe, updateJob } from "../lib/jobs";
18	
19	const CreateJobSchema = z.object({
20		kind: z.enum(["git", "linear", "pdf"]),
21		ref: z.string().min(1).max(500),
22		brand: BrandProfileSchema,
23	});
24	
25	export const videoJobRoutes = new Hono();
26	
27	videoJobRoutes.post("/", async (c) => {
28		const raw = await c.req.json().catch(() => null);
29		const parsed = CreateJobSchema.safeParse(raw);
30		if (!parsed.success) {
31			return c.json({ error: "invalid body", issues: parsed.error.issues }, 400);
32		}
33		const { kind, ref, brand } = parsed.data;
34		if (kind !== "git") {
35			return c.json({ error: "coming soon" }, 400);
36		}
37	
38		const job = createJob({
39			status: "pending",
40			progress: 0,
41			ref,
42		});
43	
44		void runPipeline(job.id, ref, brand).catch((e) => {
45			const msg = e instanceof Error ? e.message : String(e);
46			updateJob(job.id, { status: "failed", error: msg });
47		});
48	
49		return c.json({ jobId: job.id });
50	});
51	
52	videoJobRoutes.get("/:id", (c) => {
53		const job = getJob(c.req.param("id"));
54		if (!job) return c.json({ error: "not found" }, 404);
55		const { videoPath, audioPath, ...publicJob } = job;
56		return c.json({
57			...publicJob,
58			hasVideo: Boolean(videoPath),
59			hasAudio: Boolean(audioPath),
60		});
61	});
62	
63	videoJobRoutes.get("/:id/events", (c) => {
64		const id = c.req.param("id");
65		const initial = getJob(id);
66		if (!initial) return c.json({ error: "not found" }, 404);
67	
68		return streamSSE(c, async (stream) => {
69			let closed = false;
70	
71			const toPublic = (job: Job) => {
72				const { videoPath, audioPath, ...rest } = job;
73				return {
74					...rest,
75					hasVideo: Boolean(videoPath),
76					hasAudio: Boolean(audioPath),
77				};
78			};
79	
80			const send = async (job: Job) => {
81				if (closed) return;
82				await stream.writeSSE({
83					event: "status",
84					data: JSON.stringify(toPublic(job)),
85				});
86			};
87	
88			await send(initial);
89			if (initial.status === "done" || initial.status === "failed") {
90				closed = true;
91				return;
92			}
93	
94			await new Promise<void>((resolve) => {
95				const unsubscribe = subscribe(id, (job) => {
96					void send(job).then(() => {
97						if (job.status === "done" || job.status === "failed") {
98							unsubscribe();
99							closed = true;
100							resolve();
101						}
102					});
103				});
104	
105				// Re-check status after subscribing in case the job transitioned
106				// between the initial snapshot and listener registration.
107				const post = getJob(id);
108				if (post && (post.status === "done" || post.status === "failed")) {
109					void send(post).then(() => {
110						unsubscribe();
111						closed = true;
112						resolve();
113					});
114				}
115	
116				stream.onAbort(() => {
117					unsubscribe();
118					closed = true;
119					resolve();
120				});
121			});
122		});
123	});
124	
125	videoJobRoutes.get("/:id/video", (c) => {
126		const job = getJob(c.req.param("id"));
127		if (!job?.videoPath || !existsSync(job.videoPath)) {
128			return c.json({ error: "not found" }, 404);
129		}
130		const size = statSync(job.videoPath).size;
131		const nodeStream = createReadStream(job.videoPath);
132		const webStream = Readable.toWeb(nodeStream) as ReadableStream<Uint8Array>;
133		return new Response(webStream, {
134			headers: {
135				"content-type": "video/mp4",
136				"content-length": String(size),
137			},
138		});
139	});
140	
141	const inflightVoiceover = new Map<string, Promise<string>>();
142	
143	videoJobRoutes.post("/:id/voiceover", async (c) => {
144		const id = c.req.param("id");
145		const job = getJob(id);
146		if (!job) return c.json({ error: "not found" }, 404);
147		if (!job.script) {
148			return c.json({ error: "script not ready" }, 404);
149		}
150	
151		const narration = [
152			job.script.hook,
153			...job.script.scenes.map((s) => s.text),
154			job.script.closingCta,
155		].join(" ");
156	
157		let pending = inflightVoiceover.get(id);
158		if (!pending) {
159			pending = synthesizeVoice({ jobId: id, text: narration })
160				.then(({ audioPath }) => {
161					updateJob(id, { audioPath });
162					return audioPath;
163				})
164				.finally(() => {
165					inflightVoiceover.delete(id);
166				});
167			inflightVoiceover.set(id, pending);
168		}
169	
170		try {
171			await pending;
172			return c.json({ audioUrl: `/api/v1/video-jobs/${id}/audio` });
173		} catch (e) {
174			console.error(`voiceover ${id} failed:`, e);
175			return c.json({ error: "voiceover synthesis failed" }, 502);
176		}
177	});
178	
179	videoJobRoutes.get("/:id/audio", (c) => {
180		const job = getJob(c.req.param("id"));
181		if (!job?.audioPath || !existsSync(job.audioPath)) {
182			return c.json({ error: "not found" }, 404);
183		}
184		const size = statSync(job.audioPath).size;
185		const nodeStream = createReadStream(job.audioPath);
186		const webStream = Readable.toWeb(nodeStream) as ReadableStream<Uint8Array>;
187		return new Response(webStream, {
188			headers: {
189				"content-type": "audio/wav",
190				"content-length": String(size),
191				"cache-control": "no-store",
192			},
193		});
194	});
195	
196	async function runPipeline(
197		jobId: string,
198		ref: string,
199		brand: z.infer<typeof BrandProfileSchema>,
200	): Promise<void> {
201		const parsed = parseRepoUrl(ref);
202	
203		updateJob(jobId, {
204			status: "extracting",
205			progress: 10,
206			owner: parsed.owner,
207			name: parsed.name,
208		});
209		const snapshot = await fetchRepoSnapshot(ref);
210	
211		updateJob(jobId, { status: "researching", progress: 25 });
212		const market = await fetchMarketContext({
213			topic: `${snapshot.owner}/${snapshot.name} ${
214				snapshot.description ?? snapshot.primaryLanguage ?? ""
215			}`.trim(),
216		});
217	
218		updateJob(jobId, { status: "scripting", progress: 45 });
219		const script = await writeScriptFromRepo({ snapshot, brand, market });
220		updateJob(jobId, { script });
221	
222		updateJob(jobId, { status: "rendering", progress: 65 });
223		const videoPath = path.join(os.tmpdir(), `cf-${jobId}.mp4`);
224		let lastProgressTick = 65;
225		await renderVideo({
226			compositionId: "script-video",
227			inputProps: {
228				script,
229				brand,
230				repo: { owner: snapshot.owner, name: snapshot.name },
231			},
232			outputLocation: videoPath,
233			onProgress: (p) => {
234				const next = 65 + Math.round(p * 25);
235				if (next !== lastProgressTick) {
236					lastProgressTick = next;
237					updateJob(jobId, { progress: next });
238				}
239			},
240		});
241	
242		updateJob(jobId, {
243			status: "done",
244			progress: 100,
245			videoPath,
246		});
247	}
248

