1	"use client";
2	
3	import { env } from "@content-factory/env/web";
4	import type { Route } from "next";
5	import { useRouter } from "next/navigation";
6	import { useEffect, useRef, useState } from "react";
7	
8	type JobStatus =
9		| "pending"
10		| "extracting"
11		| "researching"
12		| "scripting"
13		| "rendering"
14		| "voicing"
15		| "done"
16		| "failed";
17	
18	type JobEvent = {
19		id: string;
20		status: JobStatus;
21		progress: number;
22		message?: string;
23		error?: string;
24		owner?: string;
25		name?: string;
26	};
27	
28	type StepKey =
29		| "extracting"
30		| "researching"
31		| "scripting"
32		| "rendering"
33		| "done";
34	
35	type StepState = "done" | "in-progress" | "pending";
36	
37	type StepDef = {
38		key: StepKey;
39		name: string;
40		pendingBody: string;
41		activeBody: string;
42		doneBody: string;
43	};
44	
45	const STEPS: StepDef[] = [
46		{
47			key: "extracting",
48			name: "extract_user_facing_changes",
49			pendingBody:
50				"Will scan recent commits and the README for user-facing changes.",
51			activeBody: "Reading repo metadata, README, and recent commits…",
52			doneBody: "Captured repo metadata, README, and recent commits.",
53		},
54		{
55			key: "researching",
56			name: "fetch_market_context",
57			pendingBody: "Will pull competitive context to find a unique angle.",
58			activeBody: "Searching the web for competing tools and trending hooks…",
59			doneBody: "Pulled competitive context to inform the angle.",
60		},
61		{
62			key: "scripting",
63			name: "write_voiceover_script",
64			pendingBody: "Will draft a 30-60s voiceover script in your brand voice.",
65			activeBody: "Drafting the voiceover script in your brand voice…",
66			doneBody: "Drafted the voiceover script in your brand voice.",
67		},
68		{
69			key: "rendering",
70			name: "render_scenes",
71			pendingBody: "Will render the scenes with Remotion at 9:16, 30fps.",
72			activeBody: "Rendering scenes with Remotion at 9:16, 30fps…",
73			doneBody: "Rendered the scenes with Remotion at 9:16, 30fps.",
74		},
75		{
76			key: "done",
77			name: "compose_final_video",
78			pendingBody: "Will mix scenes and brand framing into the final MP4.",
79			activeBody: "Finalizing…",
80			doneBody: "Final video ready. Voiceover available on the result page.",
81		},
82	];
83	
84	const STATUS_INDEX: Record<JobStatus, number> = {
85		pending: 0,
86		extracting: 0,
87		researching: 1,
88		scripting: 2,
89		rendering: 3,
90		voicing: 3,
91		done: 4,
92		failed: -1,
93	};
94	
95	function stepStateForStatus(idx: number, status: JobStatus): StepState {
96		if (status === "done") return "done";
97		if (status === "failed") return "pending";
98		const cursor = STATUS_INDEX[status] ?? 0;
99		if (idx < cursor) return "done";
100		if (idx === cursor) return "in-progress";
101		return "pending";
102	}
103	
104	function StatusDot({ state }: { state: StepState }) {
105		if (state === "done") {
106			return (
107				<span
108					aria-hidden
109					className="inline-block h-2 w-2 flex-none rounded-full"
110					style={{
111						background: "#2D6A4F",
112						boxShadow: "0 0 0 3px rgba(45,106,79,0.18)",
113					}}
114				/>
115			);
116		}
117		if (state === "in-progress") {
118			return (
119				<span
120					aria-hidden
121					className="brand-pulse inline-block h-2 w-2 flex-none rounded-full bg-[var(--color-magenta)]"
122				/>
123			);
124		}
125		return (
126			<span
127				aria-hidden
128				className="inline-block h-2 w-2 flex-none rounded-full border border-[var(--color-text-dim)]"
129			/>
130		);
131	}
132	
133	function FilmIcon() {
134		return (
135			<svg
136				aria-hidden="true"
137				width={18}
138				height={18}
139				viewBox="0 0 24 24"
140				fill="none"
141				stroke="currentColor"
142				strokeWidth={1.5}
143				strokeLinecap="round"
144				strokeLinejoin="round"
145			>
146				<rect x="2" y="3" width="20" height="18" rx="2" />
147				<path d="M2 8h20M2 16h20M7 3v18M17 3v18" />
148			</svg>
149		);
150	}
151	
152	export function ProgressStream({ jobId }: { jobId: string }) {
153		const router = useRouter();
154		const [job, setJob] = useState<JobEvent | null>(null);
155		const [connectionError, setConnectionError] = useState<string | null>(null);
156		const [elapsed, setElapsed] = useState(0);
157		const sourceRef = useRef<EventSource | null>(null);
158		const terminalRef = useRef(false);
159	
160		useEffect(() => {
161			const url = `${env.NEXT_PUBLIC_SERVER_URL}/api/v1/video-jobs/${jobId}/events`;
162			const source = new EventSource(url);
163			sourceRef.current = source;
164	
165			const handleStatus = (e: MessageEvent) => {
166				try {
167					const data = JSON.parse(e.data) as JobEvent;
168					setJob(data);
169					if (data.status === "done") {
170						terminalRef.current = true;
171						source.close();
172						router.replace(`/result?jobId=${jobId}` as Route);
173					}
174					if (data.status === "failed") {
175						terminalRef.current = true;
176						source.close();
177					}
178				} catch {
179					// ignore malformed event
180				}
181			};
182	
183			source.addEventListener("status", handleStatus as EventListener);
184	
185			source.onerror = () => {
186				if (terminalRef.current) return;
187				if (source.readyState === EventSource.CLOSED) {
188					setConnectionError(
189						"Lost connection to the server. Try refreshing the page.",
190					);
191				}
192			};
193	
194			return () => {
195				source.removeEventListener("status", handleStatus as EventListener);
196				source.close();
197				sourceRef.current = null;
198			};
199		}, [jobId, router]);
200	
201		useEffect(() => {
202			const start = Date.now();
203			const interval = setInterval(() => {
204				setElapsed(Math.floor((Date.now() - start) / 1000));
205			}, 1000);
206			return () => clearInterval(interval);
207		}, []);
208	
209		const status: JobStatus = job?.status ?? "pending";
210		const progress = job?.progress ?? 0;
211		const failed = status === "failed";
212		const repoLabel = job?.owner && job?.name ? `${job.owner}/${job.name}` : "—";
213		const doneCount = STEPS.filter(
214			(_s, i) => stepStateForStatus(i, status) === "done",
215		).length;
216	
217		return (
218			<>
219				<header className="grid h-14 grid-cols-[1fr_auto_1fr] items-center border-[var(--color-border)] border-b bg-[var(--color-bg)] px-6">
220					<div className="flex items-center gap-[10px] text-[13px] text-[var(--color-text-muted)]">
221						<button
222							type="button"
223							onClick={() => router.push("/source" as Route)}
224							aria-label="Back"
225							className="inline-flex h-[26px] w-[26px] cursor-pointer items-center justify-center rounded-md border border-[var(--color-border)] bg-transparent text-[var(--color-text-muted)] transition-[background-color,color] duration-[120ms] hover:bg-[var(--color-elev-1)] hover:text-[var(--color-text)]"
226						>
227							<svg
228								aria-hidden="true"
229								width={14}
230								height={14}
231								viewBox="0 0 24 24"
232								fill="none"
233								stroke="currentColor"
234								strokeWidth={1.5}
235								strokeLinecap="round"
236								strokeLinejoin="round"
237							>
238								<path d="M15 18l-6-6 6-6" />
239							</svg>
240						</button>
241						<span className="text-[var(--color-text-dim)]">/</span>
242						<span>Videos</span>
243						<span className="text-[var(--color-text-dim)]">/</span>
244						<span className="mono text-[var(--color-text)]">{repoLabel}</span>
245					</div>
246					<div className="flex min-w-[360px] flex-col items-center gap-[6px]">
247						<div className="flex items-center gap-[10px] font-medium text-[14px] text-[var(--color-text)]">
248							<span
249								className={
250									failed
251										? "inline-block h-[6px] w-[6px] rounded-full bg-[var(--color-red)]"
252										: "brand-pulse inline-block h-[6px] w-[6px] rounded-full bg-[var(--color-magenta)]"
253								}
254							/>
255							<span>{failed ? "Generation failed" : "Generating video"}</span>
256						</div>
257						<div
258							className="relative h-[2px] w-[320px] overflow-hidden rounded-[2px]"
259							style={{ background: "rgba(255,255,255,0.06)" }}
260						>
261							<div
262								className="h-full rounded-[2px] bg-[var(--color-magenta)] transition-[width] duration-[800ms]"
263								style={{ width: `${Math.max(0, Math.min(100, progress))}%` }}
264							/>
265						</div>
266					</div>
267					<div className="flex items-center justify-end gap-3">
268						<span className="mono text-[12px] text-[var(--color-text-muted)]">
269							{elapsed}s elapsed
270						</span>
271					</div>
272				</header>
273	
274				<div className="grid flex-1 grid-cols-[860px_1fr]">
275					<section className="border-[var(--color-border)] border-r px-8 pt-7 pb-10">
276						<h2 className="mb-5 flex items-center gap-2 font-medium text-[13px] text-[var(--color-text-muted)]">
277							Agent reasoning
278							<span className="mono inline-flex items-center rounded border border-[var(--color-border)] px-[6px] py-[2px] text-[11px] text-[var(--color-text-dim)]">
279								{doneCount}/{STEPS.length}
280							</span>
281						</h2>
282	
283						{failed && job?.error ? (
284							<div
285								role="alert"
286								className="mb-4 flex flex-col gap-3 rounded-md border border-[var(--color-red)] bg-[rgba(122,46,46,0.12)] p-4"
287							>
288								<div className="font-medium text-[13px] text-[var(--color-text)]">
289									Generation failed
290								</div>
291								<div className="text-[13px] text-[var(--color-text-muted)] leading-[1.55]">
292									{job.error}
293								</div>
294								<button
295									type="button"
296									onClick={() => router.push("/source" as Route)}
297									className="mono w-fit cursor-pointer rounded border border-[var(--color-border)] bg-transparent px-3 py-1 text-[12px] text-[var(--color-text-muted)] transition-[background-color,color] duration-[120ms] hover:bg-[var(--color-elev-1)] hover:text-[var(--color-text)]"
298								>
299									Try again
300								</button>
301							</div>
302						) : null}
303	
304						<div className="flex flex-col gap-3">
305							{STEPS.map((step, idx) => {
306								const state = stepStateForStatus(idx, status);
307								const body =
308									state === "done"
309										? step.doneBody
310										: state === "in-progress"
311											? step.activeBody
312											: step.pendingBody;
313								const cardBase =
314									"rounded-md border border-[var(--color-border)] p-4 transition-[background-color,border-color] duration-[160ms]";
315								const cardCls =
316									state === "in-progress"
317										? `${cardBase} bg-[var(--color-elev-2)]`
318										: state === "done"
319											? `${cardBase} bg-[var(--color-elev-1)]`
320											: `${cardBase} bg-[var(--color-elev-1)] opacity-40`;
321								const accent =
322									state === "in-progress" || state === "done"
323										? {
324												borderLeft: "2px solid var(--color-magenta)",
325												paddingLeft: "15px",
326											}
327										: undefined;
328								const shadow =
329									state === "in-progress"
330										? {
331												boxShadow:
332													"0 0 0 1px rgba(229,38,124,0.10), 0 18px 40px -24px rgba(229,38,124,0.35)",
333											}
334										: undefined;
335	
336								return (
337									<div
338										key={step.key}
339										className={cardCls}
340										style={{ ...accent, ...shadow }}
341									>
342										<div className="mb-2 flex items-center gap-[10px]">
343											<StatusDot state={state} />
344											<span className="mono flex-1 font-medium text-[13px] text-[var(--color-text)]">
345												{step.name}
346											</span>
347											{state === "in-progress" ? (
348												<span className="mono text-[11px] text-[var(--color-magenta)]">
