import { type BrandProfile, loadBrandProfile } from "@/lib/brand-profile";

import { VoiceoverButton } from "./voiceover-button";

type JobStatus =
	| "pending"
	| "extracting"
	| "researching"
	| "scripting"
	| "rendering"
	| "voicing"
	| "done"
	| "failed";

type Job = {
	id: string;
	status: JobStatus;
	progress: number;
	owner?: string;
	name?: string;
	error?: string;
};

function ArrowLeftIcon() {
