			viewBox="0 0 24 24"
			fill="none"
			stroke="currentColor"
			strokeWidth={1.5}
			strokeLinecap="round"
			strokeLinejoin="round"
		>
			<path d="M19 12H5" />
			<path d="M11 5l-7 7 7 7" />
		</svg>
