	const controller = new AbortController();
	const timer = setTimeout(() => controller.abort(), GEMINI_TIMEOUT_MS);
	try {
		const { object } = await generateObject({
			model: google(MODEL_ID),
			schema: VideoScriptSchema,
			schemaName: "VideoScript",
