			prompt: user,
			abortSignal: controller.signal,
		});
		return object;
	} catch (e) {
		if (controller.signal.aborted) {
			throw new Error(
				`gemini script generation timed out after ${GEMINI_TIMEOUT_MS}ms`,
			);
		}
		throw e;
	} finally {
		clearTimeout(timer);
	}
}

