1	import { google } from "@ai-sdk/google";
2	import { generateObject } from "ai";
3	import type { BrandProfile, MarketContext, RepoSnapshot } from "./schemas";
4	import { type VideoScript, VideoScriptSchema } from "./schemas";
5	
6	const MODEL_ID = "gemini-2.5-flash";
7	// Composer adds a hook (2.5s) + closing (2s) on top of the scene timeline.
8	// Keep these in sync with packages/composer/src/compositions/script-video.tsx.
9	const COMPOSER_PADDING_SEC = 4.5;
10	const MIN_TOTAL_SEC = 30 - COMPOSER_PADDING_SEC;
11	const MAX_TOTAL_SEC = 60 - COMPOSER_PADDING_SEC;
12	const GEMINI_TIMEOUT_MS = 60_000;
13	
14	type Args = {
15		snapshot: RepoSnapshot;
16		brand: BrandProfile;
17		market: MarketContext;
18	};
19	
20	export async function writeScriptFromRepo({
21		snapshot,
22		brand,
23		market,
24	}: Args): Promise<VideoScript> {
25		const system = systemPrompt(brand);
26		const user = userPrompt({ snapshot, market });
27	
28		const first = await runOnce({ system, user });
29		if (
30			totalSeconds(first) >= MIN_TOTAL_SEC &&
31			totalSeconds(first) <= MAX_TOTAL_SEC
32		) {
33			return first;
34		}
35	
36		const retryUser = `${user}\n\nIMPORTANT: previous draft totalled ${totalSeconds(
37			first,
38		)}s of scenes. The sum of all scenes' durationSec MUST be between ${MIN_TOTAL_SEC} and ${MAX_TOTAL_SEC} seconds (we add ${COMPOSER_PADDING_SEC}s of branding so final video is 30-60s).`;
39		const second = await runOnce({ system, user: retryUser });
40		const secs = totalSeconds(second);
41		if (secs < MIN_TOTAL_SEC || secs > MAX_TOTAL_SEC) {
42			console.warn(
43				`[agent.script] retry still out-of-bounds: ${secs}s of scenes (target ${MIN_TOTAL_SEC}-${MAX_TOTAL_SEC}s)`,
44			);
45		}
46		return second;
47	}
48	
49	async function runOnce({
50		system,
51		user,
52	}: {
53		system: string;
54		user: string;
55	}): Promise<VideoScript> {
56		const controller = new AbortController();
57		const timer = setTimeout(() => controller.abort(), GEMINI_TIMEOUT_MS);
58		try {
59			const { object } = await generateObject({
60				model: google(MODEL_ID),
61				schema: VideoScriptSchema,
62				schemaName: "VideoScript",
63				schemaDescription:
64					"Vertical short-form video script with hook + scenes + CTA",
65				system,
66				prompt: user,
67				abortSignal: controller.signal,
68			});
69			return object;
70		} catch (e) {
71			if (controller.signal.aborted) {
72				throw new Error(
73					`gemini script generation timed out after ${GEMINI_TIMEOUT_MS}ms`,
74				);
75			}
76			throw e;
77		} finally {
78			clearTimeout(timer);
79		}
80	}
81	
82	function totalSeconds(script: VideoScript): number {
83		return script.scenes.reduce((acc, s) => acc + s.durationSec, 0);
84	}
85	
86	function systemPrompt(brand: BrandProfile): string {
87		const tone = describeTone(brand);
88		return [
89			`You are a video script writer for the brand "${brand.name}".`,
90			`Voice: ${brand.voice}.`,
91			`Tone adjectives: ${tone}.`,
92			brand.rules?.dos?.length ? `Do: ${brand.rules.dos.join("; ")}.` : "",
93			brand.rules?.donts?.length ? `Don't: ${brand.rules.donts.join("; ")}.` : "",
94			`Output a vertical short-form script: a punchy hook, 4-8 scenes (each 2-8s), and a closing CTA. The sum of scene durationSec MUST be between ${MIN_TOTAL_SEC} and ${MAX_TOTAL_SEC} (the renderer adds ${COMPOSER_PADDING_SEC}s of branding so the final video is 30-60s).`,
